package main

import "fmt"

type TreeNode struct {
    Val   int
    Left  *TreeNode
    Right *TreeNode
}

func binaryTreeLevelOrderTraversal(root *TreeNode) [][]int {
    var result [][]int
    var traverse func(node *TreeNode, level int)
    traverse = func(node *TreeNode, level int) {
        if node == nil {
            return
        }
        if level == len(result) {
            result = append(result, []int{})
        }
        result[level] = append(result[level], node.Val)
        traverse(node.Left, level+1)
        traverse(node.Right, level+1)
    }
    traverse(root, 0)
    return result
}

func main() {
    // Example usage
    root := &TreeNode{1, &TreeNode{2, nil, nil}, &TreeNode{3, nil, nil}}
    result := binaryTreeLevelOrderTraversal(root)
    fmt.Println(result) // Output: [[1], [2, 3]]
}

